                        dangerouslySetInnerHTML: {
                          __html: "/** * Функция управления отображением: Либо список, Либо тур */function checkUrlRoute() {    const hash = window.location.hash; // Получаем \"#1\"    const tourContainer = document.getElementById('tour-container');    const allDetails = document.querySelectorAll('.TVHotelResulItemDetail');    if (hash && hash.startsWith('#')) {        const id = hash.substring(1); // Отрезаем решетку, получаем \"1\"        const targetDetail = document.getElementById('tour-details-' + id);        if (targetDetail) {            // Скрываем список, показываем инфо о туре            tourContainer.classList.add('TVHide');            allDetails.forEach(el => el.classList.add('TVHide'));            targetDetail.classList.remove('TVHide');            window.scrollTo(0, 0); // Поднимаем страницу вверх            return;        }    }    // Если хэша нет или он не верный — показываем список отелей    tourContainer.classList.remove('TVHide');    allDetails.forEach(el => el.classList.add('TVHide'));}// Следим за изменениями в URLwindow.addEventListener('hashchange', checkUrlRoute);// Проверяем при первой загрузкеwindow.addEventListener('DOMContentLoaded', checkUrlRoute);// Кнопка закрытия — просто очищает хэш в URLdocument.addEventListener('click', function(e) {    if (e.target.classList.contains('js-close-tour')) {        window.location.hash = '';     }});"
